/* SocialAccount.updateSocialAccount */
UPDATE TB_SOCIAL_ACCOUNT
SET NICKNAME      = #{nickname},
    PROFILE_IMAGE = #{profileImage},
    EMAIL         = #{email},
    UPT_TM        = NOW()
WHERE PROVIDER    = #{provider}
  AND PROVIDER_ID = #{providerId}

/* SocialAccount.updateLastLoginTm */
UPDATE TB_SOCIAL_ACCOUNT
SET LAST_LOGIN_TM = NOW(),
    UPT_TM        = NOW()
WHERE ID = #{id}
